import * as stylex from "@stylexjs/stylex";
import { VStack, HStack } from "@/components/ui/Stack/stack";
import { Progress } from "@/components/ui/Progress/progress";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { skeletonStyles } from "./loading-state-01.styles";

type SkeletonPattern = "text" | "card" | "table" | "avatar" | "custom";

type Props = PropsWithStylex<{
	pattern?: SkeletonPattern;
	lines?: number;
	rows?: number;
	showProgress?: boolean;
	label?: string;
	children?: React.ReactNode;
}>;

function SkeletonBar({ style }: { style?: stylex.StyleXStyles }) {
	return (
		<div
			aria-hidden="true"
			{...stylex.props(skeletonStyles.textLine, skeletonStyles.shimmer, style)}
		/>
	);
}

function TextPattern({ lines = 3 }: { lines?: number }) {
	return (
		<VStack gap="small">
			{Array.from({ length: lines }, (_, i) => (
				<SkeletonBar
					key={i}
					style={i === lines - 1 ? skeletonStyles.textLineShort : undefined}
				/>
			))}
		</VStack>
	);
}

function CardPattern() {
	return (
		<div
			{...stylex.props(skeletonStyles.cardSkeleton, skeletonStyles.shimmer)}
			aria-hidden="true"
		/>
	);
}

function TablePattern({ rows = 4 }: { rows?: number }) {
	return (
		<VStack gap="xsmall">
			<div
				{...stylex.props(skeletonStyles.tableHeader, skeletonStyles.shimmer)}
				aria-hidden="true"
			/>
			{Array.from({ length: rows }, (_, i) => (
				<div
					key={i}
					{...stylex.props(skeletonStyles.tableRow, skeletonStyles.shimmer)}
					aria-hidden="true"
				/>
			))}
		</VStack>
	);
}

function AvatarPattern() {
	return (
		<HStack gap="medium" align="center">
			<div
				{...stylex.props(skeletonStyles.avatar, skeletonStyles.shimmer)}
				aria-hidden="true"
			/>
			<div {...stylex.props(skeletonStyles.avatarTextGroup)}>
				<SkeletonBar />
				<SkeletonBar />
			</div>
		</HStack>
	);
}

export function LoadingState01({
	pattern = "text",
	lines,
	rows,
	showProgress,
	label = "Loading content",
	children,
	style,
}: Props) {
	return (
		<output
			aria-busy="true"
			aria-label={label}
			{...stylex.props(skeletonStyles.container, style)}
		>
			{pattern === "text" && <TextPattern lines={lines} />}
			{pattern === "card" && <CardPattern />}
			{pattern === "table" && <TablePattern rows={rows} />}
			{pattern === "avatar" && <AvatarPattern />}
			{pattern === "custom" && children}

			{showProgress && (
				<div {...stylex.props(skeletonStyles.progressWrapper)}>
					<Progress value={null} />
				</div>
			)}
		</output>
	);
}

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { spacing, borderRadius } from "@/lib/theme/tokens.stylex";

const shimmer = stylex.keyframes({
	"0%": { transform: "translateX(-100%)" },
	"100%": { transform: "translateX(100%)" },
});

export const skeletonStyles = stylex.create({
	shimmer: {
		position: "relative",
		overflow: "hidden",
		"::after": {
			content: "",
			position: "absolute",
			inset: 0,
			background: `linear-gradient(90deg, transparent 0%, ${theme.surfaceRaised} 50%, transparent 100%)`,
			animationName: shimmer,
			animationDuration: {
				default: "1.5s",
				"@media (prefers-reduced-motion: reduce)": "0ms",
			},
			animationIterationCount: "infinite",
			animationTimingFunction: "ease-in-out",
		},
	},

	textLine: {
		height: 14,
		borderRadius: borderRadius.full,
		backgroundColor: theme.surfaceSubtle,
	},

	textLineShort: {
		width: "60%",
	},

	cardSkeleton: {
		height: 200,
		borderRadius: theme.borderRadius,
		backgroundColor: theme.surfaceSubtle,
	},

	tableHeader: {
		height: 40,
		borderRadius: theme.borderRadius,
		backgroundColor: theme.surfaceSubtle,
		marginBottom: spacing.xsmall,
	},

	tableRow: {
		height: 48,
		borderRadius: theme.borderRadius,
		backgroundColor: theme.surfaceSubtle,
	},

	avatar: {
		width: 48,
		height: 48,
		borderRadius: "50%",
		backgroundColor: theme.surfaceSubtle,
		flexShrink: 0,
	},

	avatarRow: {
		display: "flex",
		flexDirection: "row",
		alignItems: "center",
		gap: spacing.medium,
	},

	avatarTextGroup: {
		display: "flex",
		flexDirection: "column",
		gap: spacing.xsmall,
		flex: 1,
	},

	container: {
		display: "flex",
		flexDirection: "column",
		gap: spacing.medium,
		padding: spacing.medium,
	},

	progressWrapper: {
		marginTop: spacing.small,
		width: "100%",
		maxWidth: 300,
	},
});
